function fetch_response()  
    local resp_body        -- HTTP body
    local resp_code, resp_headers
    
    -- Set default MIME
    mime.default_mime("html")
    
    -- Make GET request and store response in resp table
    -- For testing purpose use req.url
    resp = ngx.location.capture(req_args['url'], {query="args="..table.concat(req_args)}) 
    
    if not resp then
        return nil, "failed to fetch URL: "..req_args["url"] .. ", check your request." 
    else
        -- If URL contains content-type, set it as default for further processing.
        if (resp and resp.status == 200) then
            local content = string.match(resp.header['content-type'], "[^;]+")
            
            if not content or #content < 1 then
                mime.default_mime("html")
            else
                -- Update MIME to handle content-types other than html
                mime.set_default_mime(content) 
            end
        elseif (req_args['url']:find("?args=") ~= nil) then
            resp = ngx.location.capture(req_args['url'], {query="args="..table.concat(req_args)})
            mime.default_mime("html")
        else
            return "failed to fetch URL: "..req_args["url"] .. ", check your request." 
        end

        resp_body = (resp and type(resp.data) == "string" and resp.data or nil )
        resp_code  = (resp and resp.status         ==   200       and  200       or nil )  
        resp_headers = {}
        for k,v in pairs(resp.header) do 
            table.insert(resp_headers, {key=k,value=v})
        end 

        return resp_code, resp_body, resp_headers
    end
end


